-- V9: качественные KZ-дистрибьюторы (веб-верификация 2026-07-08; per-claim источники в .superpowers/research/dist-*.md и gap-*.md).
-- Обновляет 10 из V8 (email + исправленные бренды/виды МИ по сайтам) и добавляет 10 новых → 20 всего.
-- email на generic-доменах / не найденные — верифицировать перед боевой рассылкой (⚠ ниже).
-- Виды МИ смапплены на ТОЧНЫЕ имена equipment_type (V1+V7) — иначе join молча теряет строку.

-- ═══════════ ЧАСТЬ 1: обновление 10 существующих (из V8) ═══════════

-- 1a. email (публичные адреса с сайтов; ⚠ = перепроверить)
UPDATE distributor SET email='yes@medsyst.kz'       WHERE market='KZ' AND name='ТОО «MEDSYST (МЕДСИСТ)»';                 -- ⚠ необычный логин, но опубликован на /contacts
UPDATE distributor SET email='info@rahmed.kz'        WHERE market='KZ' AND name='ТОО «РАХМЕД АЗИЯ»';
UPDATE distributor SET email='info@neomedrem.kz'     WHERE market='KZ' AND name='ТОО «НЕОМЕДРЕМ»';
UPDATE distributor SET email='info@vz-med.kz'        WHERE market='KZ' AND name='ТОО «ВЗМед»';
UPDATE distributor SET email='info@medico-intech.kz' WHERE market='KZ' AND name='ТОО «Медико-Инновационные Технологии»';
UPDATE distributor SET email='sales@iskra.kz'        WHERE market='KZ' AND name='ТОО «Искра Трэйдинг»';                    -- ⚠ домен iskra.kz (не iskra-trading.kz)
UPDATE distributor SET email='info@adent.kz'         WHERE market='KZ' AND name='ТОО «Астра-Дент»';                        -- ⚠ домен adent.kz
UPDATE distributor SET email='7su-med@mail.ru'       WHERE market='KZ' AND name='ТОО «Жетысу-Мед»';                        -- ⚠ mail.ru
UPDATE distributor SET email='sales.kz@btlnet.com'   WHERE market='KZ' AND name='ТОО «BTL Kazakhstan»';
UPDATE distributor SET email='office@bhp.kz'         WHERE market='KZ' AND name='ТОО «БиоХимПрибор»';

-- 1b. сброс брендов и видов МИ 10 существующих (пере-вставка исправленных наборов ниже, в ЧАСТИ 3)
DELETE FROM distributor_brand WHERE distributor_id IN (
  SELECT id FROM distributor WHERE market='KZ' AND name IN (
    'ТОО «MEDSYST (МЕДСИСТ)»','ТОО «РАХМЕД АЗИЯ»','ТОО «НЕОМЕДРЕМ»','ТОО «ВЗМед»','ТОО «Медико-Инновационные Технологии»',
    'ТОО «Искра Трэйдинг»','ТОО «Астра-Дент»','ТОО «Жетысу-Мед»','ТОО «BTL Kazakhstan»','ТОО «БиоХимПрибор»'));
DELETE FROM distributor_equipment_type WHERE distributor_id IN (
  SELECT id FROM distributor WHERE market='KZ' AND name IN (
    'ТОО «MEDSYST (МЕДСИСТ)»','ТОО «РАХМЕД АЗИЯ»','ТОО «НЕОМЕДРЕМ»','ТОО «ВЗМед»','ТОО «Медико-Инновационные Технологии»',
    'ТОО «Искра Трэйдинг»','ТОО «Астра-Дент»','ТОО «Жетысу-Мед»','ТОО «BTL Kazakhstan»','ТОО «БиоХимПрибор»'));

